private static volatile Singleton instance;
public static Singleton getInstance() {
    if (instance == null) {
        synchronized (Singleton.class) {
            if (instance == null) {
                instance = new Singleton(); // 非原子:分配内存->初始化->赋值
            }
        }
    }
    return instance;
}
// 不加 volatile,指令重排可能把「赋值」排到「初始化」之前,其他线程拿到未初始化完的对象。
